<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Operation "Veil of Maya" — Scale and Laundering Flow</text>
  <g font-family="sans-serif">
    <rect x="30" y="54" width="150" height="82" rx="10" fill="#2a1a0e" stroke="#fb923c" stroke-width="1.3"/>
